import{_ as e,c as s,o,a}from"./app.a34a8c50.js";const f='{"title":"Home","description":"","frontmatter":{"home":true,"heroImage":"/solarplexus-logo.svg","heroAlt":"Solarplexus logo","heroText":"Solarplexus","tagline":"Close to the heart of Gutenberg","actionText":"Download for Wordpress >= 5.9","actionLink":"https://github.com/Aventyret/solarplexus/releases","footer":"MIT Licensed | Copyright \xA9 2021-present \xC4ventyret"},"headers":[{"level":2,"title":"What is Solarplexus?","slug":"what-is-solarplexus"},{"level":2,"title":"Gutenberg on Steroids \u{1F4AA}","slug":"gutenberg-on-steroids-\u{1F4AA}"}],"relativePath":"index.md"}',t={},r=a('<div class="grid"><div class="grid-col grid-col--6"><h2 id="what-is-solarplexus" tabindex="-1">What is Solarplexus? <a class="header-anchor" href="#what-is-solarplexus" aria-hidden="true">#</a></h2><p><strong>Solarplexus</strong> is a plugin aimed for developers of complex custom Wordpress websites. Solarplexus gives developers a powerful tool for adding <strong>dynamic display blocks</strong> (as in \u201Cvarious ways of displaying content [in a page/post] that is residing in other areas of your website\u201D).</p><p>We created Solarplexus because when building websites that stays <strong>close to Core</strong> (i.e. accepts and celebrates the new Wordpress Block Editor (a.k.a. Gutenberg) there was a clear need for a standardized way of bringing life to feed based websites also in the new era of Wordpress.</p><p>Solarplexus is created by <a href="https://aventyret.com" target="_blank" rel="noopener noreferrer">\xC4ventyret</a> \u2013 a leading Wordpress (and much more) agency in Sweden \u2013 as our way to give back to the Wordpress community that has given us so much. Solarplexus is open source software free to use for anyone.*</p><hr><p><em>* Bare in mind Solarplexus is not the most graspable plugin around (at least not yet, hence why we call it a \u201Cdeveloper plugin\u201D) so you probably need a few years of experience in Wordpress development if you want to use it sucessfully.</em></p></div><div class="grid-col grid-col--6"><h2 id="gutenberg-on-steroids-\u{1F4AA}" tabindex="-1">Gutenberg on Steroids \u{1F4AA} <a class="header-anchor" href="#gutenberg-on-steroids-\u{1F4AA}" aria-hidden="true">#</a></h2><p>We think the Block editor (a.k.a Gutenberg) is a great idea while not yet a great implementation. Building Wordpress websites in an agency environment since 2003, we \u2013 a group of developers \u2013 were missing a (for us) central piece of the puzzle: blocks displaying content from other parts of the same website.</p><p>Solarplexus is <strong>our solution to the problem</strong>. With the Solarplexus plugin a developer can create a custom set of blocks through writing just a few lines of code.</p><p><a href="https://github.com/Aventyret/solarplexus/releases" target="_blank" rel="noopener noreferrer">Download it</a> today, checkout our <a href="/solarplexus/guide/">getting started guide</a>. Try it out and <a href="https://github.com/Aventyret/solarplexus" target="_blank" rel="noopener noreferrer">join us on Github</a> developing it further!</p><div class="facts"><h3>Perks with Solarplexus</h3><div class="facts-item"><span>\u{1F44C}</span><div> Create dynamic or handpicked lists of articles (or other post types) to be displayed on Block editor based pages/posts </div></div><div class="facts-item"><span>\u{1F3A8}</span><div> Support for Sage or standard theme development </div></div><div class="facts-item"><span>\u{1F4A3}</span><div> Powerful customization </div></div><div class="facts-item"><span>\u26A1</span><div> Lightning fast setup </div></div></div></div></div><div class="home-footer"><div class="home-footer-inner"><h2>Fun Facts</h2><div class="grid"><div class="grid-col grid-col--6"><div class="home-footer-fact"><span>1</span><div> Solarplexus borrows its name from the iconic Swedish jazz rock band Solar Plexus, founded 1969. Pioneering the genre of \u2018acid jazz\u2019 Solar Plexus were famous for playing a mix between folk music, prog and psychadelica. And since Wordpress names all major releases after jazz legends, we \u2013 being Swedish\u2013 thought it would be suitable to name our contribution to the community after the Swedish leading contributors to jazz (with a folky rock n\u2019 roll twist). </div></div></div><div class="grid-col grid-col--6"><div class="home-footer-fact"><span>2</span><div> The celiac plexus, also known as the solar plexus because of its radiating nerve fibers, is a complex network of nerves (a nerve plexus) located in the abdomen, near where the celiac trunk, superior mesenteric artery, and renal arteries branch from the abdominal aorta. Or as we would say: close to the Core. </div></div></div></div></div></div>',2),i=[r];function n(l,d,c,p,u,h){return o(),s("div",null,i)}var v=e(t,[["render",n]]);export{f as __pageData,v as default};
